window.__QUIZ_DATA__=[{"id":"objective>Physics>1999>1","subject":"Physics","year":"1999","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"The force between molecules of the same substance is termed","images":[],"options":{"A":"elastic force","B":"repulsive force","C":"cohesive force","D":"adhesive force"},"answer":"C","explanation":"Cohesive force is the force of attraction between similar molecules. For example, the force that holds water molecules together is cohesive force.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>2","subject":"Physics","year":"1999","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A net force of magnitude 0.6 N acts on a body of mass 40 g, initially at rest. Calculate the magnitude of resulting acceleration","images":[],"options":{"A":"90 ms-2","B":"60 ms-2","C":"30 ms-2","D":"15 ms-2"},"answer":"D","explanation":"Using the formula F = ma, where F is the force, m is the mass and a is the acceleration. Rearranging the formula, we get a = F/m. Substituting the given values, we get a = 0.6N / 0.04kg = 15 ms-2.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>3","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Palm oil from a bottle flows out more easily after it has been heated because the","images":[],"options":{"A":"molecules are given potential energy during the heating","B":"friction between oil layers is reduced","C":"oil molecules force each other out","D":"adhesion between the oil molecules and those of the bottle is increased"},"answer":"B","explanation":"If a liquid is heated the particles are given more energy and move faster and faster expanding the liquid.The result is that liquids show a reduction in viscosity (internal friction) with increasing temperature.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>4","subject":"Physics","year":"1999","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"A body weighing 100 N moves with a speed of 5 ms-1 in a horizontal circular path of radius 5 m. Calculate the magnitude of the centripetal force acting on the body.  [g = 10 ms-2]","images":[],"options":{"A":"10 N","B":"50 N","C":"75 N","D":"100 N"},"answer":"B","explanation":"W=100N;g=10ms-2;v=5ms-1;r=5m;W=mg;m=Wg=10010=10 kg   \u2234F=mv2r=10 x 525=10x5=50N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>5","subject":"Physics","year":"1999","type":"Objective","topic":"MOTION : RELATIVE MOTION","question":"A motor-cyclist, passing a road junction, moves due west for 8 s at a uniform speed of 5 ms-1. He then moves due north for another 6 s with the same speed. At the end of the 6 s his displacement from the road junction is 50 m in the direction of","images":[],"options":{"A":"N53oE","B":"N37oE","C":"N53oW","D":"N37oW"},"answer":"C","explanation":"due west distance covered = 8 x 5 = 40 m    due north distance covered = 6 x 5 = 30 m  tan\u03b8=4030=43  \u03b8=tan-143  \u03b8 = 53o    \u2234 direction is N53oW","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>6","subject":"Physics","year":"1999","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF VELOCITY","question":"The time rate of change of displacement is known as","images":[],"options":{"A":"speed","B":"velocity","C":"impulse","D":"acceleration"},"answer":"B","explanation":"The time rate of change of displacement is known as velocity. Velocity is a vector quantity that refers to 'the rate at which an object changes its position'. In other words, velocity is speed in a given direction. Speed, on the other hand, is a scalar quantity that refers to 'how fast an object is moving'. Impulse is the change in momentum of an object when the object is acted upon by a force for an interval of time. Acceleration is the rate of change of velocity per unit of time.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>7","subject":"Physics","year":"1999","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"A stone of mass 0.7 kg is projected vertically upwards with a speed of 5 ms-1. Calculate the maximum height reached.  [Take g as 10 ms-2 and neglect air resistance]","images":[],"options":{"A":"1.00 m","B":"1.25 m","C":"1.50 m","D":"3.75 m"},"answer":"B","explanation":"m = 0.7 kg; u = 5 ms-1; g = 10 ms-2; hmax = ?; At maximum height, v = 0    v2 = u2 - 2gs (g = -ve)    0 = 52 - 2 x 10 x hmax    2 x 10 x hmax = 52    20hmax = 25    \u2234hmax=2520=1.25m","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>8","subject":"Physics","year":"1999","type":"Objective","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"If the force of attraction between the sun and the planets is removed, the planets will","images":[],"options":{"A":"fall towards the sun","B":"scatter and stop moving","C":"continue to move at tangent to their original orbit","D":"continue to move perpendicular to their original orbits"},"answer":"C","explanation":"Gravitational force acts between the sun and the planets, which causes the planets to orbit around the sun.    If this force between sun and the planets is removed, the path of motion of the planet is disturbed, and the planets start traveling along the straight path tangential to their orbital path out in the free space.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>9","subject":"Physics","year":"1999","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A 15 kg mass suspended from a ceiling is pulled aside with a horizontal force, F as shown in the diagram beside. Calculate the value of the tension T  [g = 10 ms-1]","images":["data:image/png;base64,"],"options":{"A":"300.0 N","B":"173.2 N","C":"30.0 N","D":"17.3 N"},"answer":"B","explanation":"cos\u03b8=adjhyp  cos30o=mgT=15 x 10T=150T  Tcos30o=150  \u2234T=150cos 30o=173.2N","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>10","subject":"Physics","year":"1999","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"A pendulum bob executing simple harmonic motion has 2 cm and 12 Hz as amplitude and frequency respectively. Calculate the period of the motion.","images":[],"options":{"A":"2.00 s","B":"0.83 s","C":"0.08 s","D":"0.06 s"},"answer":"C","explanation":"The period of a pendulum bob executing simple harmonic motion is the reciprocal of the frequency. Given that the frequency is 12 Hz, the period of the motion is 1/12 = 0.08333 s, which is approximately 0.08 s.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>11","subject":"Physics","year":"1999","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : THIRD LAW","question":"A trolley of mass 4 kg moving on a smooth horizontal platform with a speed of 1.0 ms-1 collides perfectly with a stationary trolley of the same mass on the same platform. Calculate the total momentum of the two trolleys immediately after the collision","images":[],"options":{"A":"0.5 Ns","B":"1.0 Ns","C":"4.0 Ns","D":"8.0 Ns"},"answer":"C","explanation":"The law of conservation of energy states that  pinitial = pfinal  So, the total momentum  p = mv = 4 x 1 = 4.0 Ns","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>12","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The ice point of an ungraduated mercury-in-glass thermometer is X, while its steam point is 90o. This thermometer reads 60o when the true temperature is 40oC. Calculate the value of X","images":[],"options":{"A":"60o","B":"48o","C":"40o","D":"30o"},"answer":"C","explanation":"Sincethetemperatureisthesame  ==>60 - x90 - x=40 - 0100 - 0==>100(60-x)=40(90-x)  =6000-100x=3600-40x  =6000-3600=100x-40x  =2400=60x  \u2234x=240060=40o","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>13","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Iron at 30oC feels cooler to the hand than wood at 28oC because","images":[],"options":{"A":"their linear expansivities are not equal","B":"the temperature of the iron higher than that of the wood","C":"iron is a better radiator of heat than wood","D":"iron conducts heat more quickly from the hand than wood"},"answer":"D","explanation":"Iron at 30oC feels cooler to the hand than wood at 28oC because iron conducts heat more quickly from the hand than wood","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>14","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"An iron rod of length 50 m at a temperature of 60oC is heated to 70oC. Calculate its new length  [Linear expansivity of iron = 1.2 x 10-5 K-1]","images":[],"options":{"A":"50.006 m","B":"50.060 m","C":"51.600 m","D":"51.200 m"},"answer":"A","explanation":"L1=50m;\u03b81=60oC;\u03b82=70oC;L2=?;\u03b1=1.2x10-5K  \u03b1=L2 - L1L1(\u03b82 - \u03b81)==>L2=L1(1+\u03b1(\u03b82-\u03b81))  =L2=50(1+1.2x10-5x(70-60))=50(1+1.2x10-5x10)  =L2=50(1+0.00012)=50(1.00012)  \u2234L2=50.006m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>15","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"The heat capacity of a substance is the energy","images":[],"options":{"A":"required to raise the temperature of a unit mass of the substance by one degree","B":"required to raise the temperature of the substance by one degree","C":"absorbed by the substance at constant temperature","D":"lost by a unit mass of the substance"},"answer":"B","explanation":"The heat capacity of a substance is the energy required to raise the temperature of the substance by one degree","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>16","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"The temperature of a piece of metal of mass 9 g is raised from 10oC to 110oC when it absorbs 108 J of heat energy. Determine the specific heat capacity of the metal in Jkg-1K-1","images":[],"options":{"A":"1.2","B":"12.0","C":"120.0","D":"1200.0"},"answer":"C","explanation":"m = 9 g = 0.009 kg; \u03b81 = 10oC; \u03b82 = 110oC; H = 108 J; c = ?  H = mc\u0394\u03b8  = 108 = 0.009 x c x (110 - 10)  = 108 = 0.009 x c x 100  = 108 = 0.9c  \u2234c=1080.9=120.0Jkg-1K-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>17","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Which of the following statements is not correct","images":[],"options":{"A":"A sea breeze is due to convection in air","B":"Cotton materials are better than the woollen ones for use in hot weather","C":"Convectional currents play an important role in the cooling of the engine of a motor car","D":"the vacuum space in a flask helps to reduce heat loss by radiation"},"answer":"D","explanation":"All the statements are correct except for the last one. A vacuum flask reduces heat loss by preventing conduction and convection, not radiation. The vacuum space in a flask prevents heat transfer by conduction and convection because these processes require a medium (solid, liquid, or gas) to occur. However, heat can still be transferred by radiation, which does not require a medium. The flask's reflective inner surface helps to reduce this radiative heat loss by reflecting radiated heat back into the flask.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>18","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"Calculate the heat energy required to change 0.1 kg of ice at 0oC to water boiling at 100oC.  [Specific heat capacity of water = 4200 Jkg-1K-1]  [Specific latent heat of fusion of ice = 336,000 Jkg-1]","images":[],"options":{"A":"75,600 J","B":"336,000 J","C":"340,200 J","D":"378,000 J"},"answer":"A","explanation":"H = mL + mc\u0394\u03b8 = m(L + c\u0394\u03b8)  H = 0.1(336000 + 4200(100 - 0) = 0.1(336000 + 4200 x 100)  H = 0.1(336000 + 420000) = 0.1 x 756000  \u2234 H = 75,600 J","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>19","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : EVAPORATION AND BOILING","question":"Which of the following statements about evaporation is not correct?","images":[],"options":{"A":"The rate of evaporation of a liquid varies with temperature","B":"The molecules of an evaporating liquid have an average speed","C":"Evaporation occurs when faster molecules escape from the surface of a liquid","D":"Evaporation takes place inside a liquid"},"answer":"D","explanation":"Evaporation takes place only at the surface of a liquid, whereas boiling may occur throughout the liquid.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>20","subject":"Physics","year":"1999","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"Calculate the power rating of an immersion heater used for 10 minutes to increase the temperature of 10 kg of water by 15 K.  [Specific heat capacity of water = 4200 Jkg-1K-1]","images":[],"options":{"A":"1,050 W","B":"16,800 W","C":"18,060 W","D":"20,160 W"},"answer":"A","explanation":"m = 10 kg; \u0394\u03b8 = 15 K; c = 4200 Jkg-1K-1; t = 10 minutes = 10 x 60 = 600 s; H = mc\u0394\u03b8  H = 10 x 4200 x 15 = 630,000 J  \u2234P=Ht=630,000600=1,050W","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>21","subject":"Physics","year":"1999","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"A ray of light is incident on a plane mirror at an angle of 20o. This mirror is rotated through, twice this angle. In this new position, the angle between the incident ray and the reflected ray is","images":[],"options":{"A":"20o","B":"40o","C":"80o","D":"120o"},"answer":"D","explanation":"i = 20o; \u03b8 = 2 x 20o = 40o  Angle between incident ray ON and the new reflected ray NR2 = ONR2 = (i + \u03b8) + (i + \u03b8) = 2(i + \u03b8)  \u2234 the angle between the incident ray and the reflected ray = 2(20 + 40) = 2 x 60 = 120o","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>22","subject":"Physics","year":"1999","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES","question":"The air column in a resonance tube is set into resonance by a vibrating tuning fork. The resultant waves in the air column will be","images":[],"options":{"A":"mechanical and transverse","B":"progressive and longitudinal","C":"stationary and transverse","D":"stationary and longitudinal"},"answer":"D","explanation":"When air that is set  into vibration by a tuning fork  vibrates inside a resonance tube, the waves produced are reflected at the ends producing a longitudinal stationary wave along the length of the resonance tube, thus a loud sound is heard.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>23","subject":"Physics","year":"1999","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"The image of a object is located 6 cm behind a convex mirror. If its magnification is 0.6, calculate the focal length of the mirror","images":[],"options":{"A":"3.75 cm","B":"6.60 cm","C":"10.00 cm","D":"15.00 cm"},"answer":"D","explanation":"v=-6cm;m=0.6;m=vu==>0.6=6u;u=60.6=10cm  but1f=1u+1v  1f=110-16(v=-ve)  1f=6 - 1060  1f=-460  1f=-115  f=-15(focallengthofadivergingmirrorisnegative)  \u2234f=15.00cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>24","subject":"Physics","year":"1999","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The refractive index of glass for yellow light is greater than that for red light because yellow light","images":[],"options":{"A":"has a greater amplitude than red light","B":"is more intense than red light","C":"travels more slowly than than red light","D":"deviates less than red light"},"answer":"C","explanation":"Refractive index is inversely proportional to wavelength. Yellow has lower wavelength compares to red. And that is why the refractive index is more in yellow light in the glass.    Wavelength is directly proportional to speed. Yellow light having a lower wavelength will have a slower speed than red light","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>25","subject":"Physics","year":"1999","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The real image of an object formed by a converging lens of focal length 15 cm is three times the size of the object. Calculate the object distance","images":[],"options":{"A":"60 cm","B":"30 cm","C":"20 cm","D":"15 cm"},"answer":"C","explanation":"f=15cm;m=3;u=?;m=vu==>3=vu;v=3u  but1f=1u+1v  115=1u+13u(sincev=3u)  115=3 + 13u  115=43u  15=3u4  15x4=3u  \u2234u=5x4=20cm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>26","subject":"Physics","year":"1999","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"Which of the following statements is not correct about long sight?","images":[],"options":{"A":"A long-sighted person can see distant objects clearly","B":"light from a nearby object is focused behind the retina","C":"The eyeball is too short","D":"The defect is corrected by using a diverging lens."},"answer":"D","explanation":"Long sightedness, also known as hypermetropia, is a common eye condition where nearby objects appear blurred, while far objects can be seen clearly. This happens when the light that enters the eye is focused behind the retina, rather than directly on it. This is often because the eyeball is too short. However, the defect is corrected by using a converging lens, not a diverging lens. A converging lens is a lens that converges rays of light that are traveling parallel to its axis. It is thicker in the middle than at the edges.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>27","subject":"Physics","year":"1999","type":"Objective","topic":"PROPERTIES OF WAVES : SUPERPOSITION","question":"The amplitude of a wave is the","images":[],"options":{"A":"distance between two successive troughs of the wave","B":"separation of two adjacent particles vibrating in phase","C":"maximum displacement of the wave particle from the equlibrium position","D":"distance travelled by a wave in complete cycle of its motion."},"answer":"C","explanation":"The amplitude of a wave is the maximum displacement of the wave particle from the equlibrium position","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>28","subject":"Physics","year":"1999","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"In order to obtain a sound note of a high pitch from a wire stretched by a constant tension, the wire must be","images":[],"options":{"A":"short and thick","B":"short and thin","C":"long and thick","D":"long and thin"},"answer":"B","explanation":"The pitch depends on frequency  and frequency is inversely proportional to length and mass density of the wire. So, the shorter the length of the wire, the more the frequency of the wire. Also the thinner the wire, the lesser the mass density and as a result, the more the frequency of the wire.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>29","subject":"Physics","year":"1999","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"If the position of resonance in a resonance tube is 16.50 cm from the open end of the tube, calculate the distance from the open end to the next position where resonance occurs.  [Neglect end-correction]","images":[],"options":{"A":"24.70 cm","B":"33.00 cm","C":"41.25 cm","D":"49.50 cm"},"answer":"D","explanation":"L=\u03bb4=16.5 cm(forfirstresonance)  \u03bb=4x16.5=66cm  L=3\u03bb4=3 x 664=49.50cm(atnextresonance)","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>30","subject":"Physics","year":"1999","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"Thunder is usually heard some seconds after lightning is observed because","images":[],"options":{"A":"the human eye is more sensitive to light than the ear to sound","B":"sound and light travel in different media","C":"thunder occurs after lightning","D":"light travels faster than sound"},"answer":"D","explanation":"A person on the ground sees lightning flash before hearing the thunder because light at a speed of around 3.0 x 108 ms-1 travels much faster than sound which moves at 330 ms-1.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>31","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Using the diagram below, calculate the effective capacitance of the circuit.","images":["data:image/png;base64,"],"options":{"A":"1.56 \u03bcf","B":"3.00 \u03bcf","C":"3.71 \u03bcf","D":"9.00 \u03bcf"},"answer":"A","explanation":"LetCbetheeffectivecapacitanceandC1bethecapacitanceinparallel==>C1=3+4=7\u03bcf  \u22341C=12+17=7 + 214  =1C=914  \u2234C=149=1.56\u03bcf","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>32","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"Using the data on the diagram below, calculate the potential difference across the 20 \u03a9 resistor.  [Neglect the internal resistance of the cell]","images":["data:image/png;base64,"],"options":{"A":"5 V","B":"10 V","C":"20 V","D":"60 V"},"answer":"D","explanation":"The P.d V1 across the 5 \u03a9 wire = IR = 2 x 5 = 10 V  \u2234Currentthroughthe10\u03a9wire=V1R=1010=1A  \u2234 Total current across 20 \u03a9 wire = 1 + 2 = 3 A  \u2234 P.d V2 across 20 \u03a9 wire = IR = 3 x 20 = 60 V","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>33","subject":"Physics","year":"1999","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"The parts of a bar magnet at which the magnetic effect is strongest are called the","images":[],"options":{"A":"poles","B":"neutral points","C":"magnetic declination","D":"magnetic meridians"},"answer":"A","explanation":"A magnetic pole is the part of a magnet that exerts the strongest force on other magnets or magnetic material, such as iron.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>34","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"A resistance wire of length 2 m and of uniform cross sectional area 5.0 x 10-7 m2 has a resistance of 2.2 \u03a9. Calculate its resistivity","images":[],"options":{"A":"1.8 x 10-7 \u03a9m","B":"5.5 x 10-7 \u03a9m","C":"1.8 x 107 \u03a9m","D":"5.5 x 107 \u03a9m"},"answer":"B","explanation":"R=\u03c1LA  i.e2.2=\u03c1 x 25.0 x 10-7  2.2x5.0x10-7=2\u03c1  \u2234\u03c1=2.2 x 5.0 x 10-72=11 x 10-72=5.5x10-7\u03a9m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>35","subject":"Physics","year":"1999","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"Magnetic flux density is defined as the","images":[],"options":{"A":"total number of magnetic lines of force surrounding a magnet","B":"number of magnetic lines of force per unit area normal to the magnetic field","C":"strength of the magnetic field sorrounding a current carrying conductor","D":"magnetic force exerted on a unit magnetic pole"},"answer":"B","explanation":"The magnetic flux density or magnetic induction is the number of lines of force passing through a unit area of material, B. The unit of magnetic induction is the tesla (T).","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>36","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"The voltage and current in the primary of a transformer are 200 V and 2 A respectively. If the transformer is used to light ten 12 V, 30 W bulbs, calculate its efficiency.","images":[],"options":{"A":"100%","B":"90%","C":"75%","D":"50%"},"answer":"C","explanation":"Power supplied to primary cell = IV = 2 x 200 = 400 W  Power developed in secondary cell = 10 x 30 = 300 W  \u03b5=P.SP.Px100%  ==>\u03b5=300400x100%  \u2234 \u03b5 = 75%","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>37","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"In a uniform electric field, the magnitude of the force on a charge of 0.2 C is 4 N. Calculate the electric field intensity","images":[],"options":{"A":"20 NC-1","B":"8 NC-1","C":"5 NC-1","D":"2 NC-1"},"answer":"A","explanation":"The electric field intensity is defined as the force experienced by a unit positive charge placed in the field. It can be calculated using the formula E = F/q, where E is the electric field intensity, F is the force, and q is the charge. Substituting the given values, we get E = 4N / 0.2C = 20 NC-1.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>38","subject":"Physics","year":"1999","type":"Objective","topic":"GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY","question":"A rocket of mass m is fired from the earth's surface such that it just escapes from the earth's gravitational field. If R is the radius of the earth and g the acceleration of free fall due to gravity, the escape velocity of the rocket is expressed as","images":[],"options":{"A":"\u221a2gR","B":"\u221a2/Rg","C":"\u221a2g/R","D":"\u221aR2/2g"},"answer":"A","explanation":"The escape velocity of a rocket is given by the formula v = \u221a(2gR), where g is the acceleration due to gravity and R is the radius of the Earth. This formula is derived from the principle of conservation of energy, which states that the total energy of an isolated system remains constant. In this case, the kinetic energy of the rocket (1/2 mv^2) is equal to the gravitational potential energy (mgh) at the point of escape. Solving for v gives the escape velocity.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>39","subject":"Physics","year":"1999","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"A 10 \u03a9 coil takes 21 s to melt 10 g of ice at 0oC. Assuming no heat losses, determine the current in the coil.  [Specific latent heat of fusion = 336 Jg-1]","images":[],"options":{"A":"16 A","B":"5 A","C":"4 A","D":"3 A"},"answer":"C","explanation":"I2Rt = mL  ==> I2 x 10 x 21 = 10 x 336  = I2 x 210 = 3360  =I2=3360210=16  \u2234 I = \u221a16 = 4 A","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>40","subject":"Physics","year":"1999","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"A point charge of magnitude 2 \u03bcC is moved through a distance of 0.20 m against a uniform field of intensity 25 Vm-1. Calculate the workdone on the charge.","images":[],"options":{"A":"5.0 x 10-6 J","B":"1.0 x 10-5 J","C":"5.0 x 10-5 J","D":"1.0 x 10-2 J"},"answer":"B","explanation":"W = QV; but V = Ed; E = electric intensity  ==> V = 25 x 0.2 = 5 V  \u2234 W = 2 x 10-6 x 5 = 1.0 x 10-5 J","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>41","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Bohr's atomic model proves most successful for the explanation of the:  I. structure of the hydrogen atom  II. line spectra of the hydrogen atom  III. multi-electron atoms  Which of the following statements is/are correct?","images":[],"options":{"A":"I only","B":"II only","C":"I and II only","D":"I and III only"},"answer":"C","explanation":"The model's key success lay in explaining the Rydberg formula for hydrogen's spectral emission lines.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>42","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Use the diagram above to answer Questions below     The diagram above illustrates the energy transitions of five electrons of an atom. Which of the transitions will produce the emission of longest wave length?","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"The one with the least energy produces the longest wavelength  \u0394E for I = 0.0 - (-2.6) = 0.0 + 2.6 = 2.6 eV (which is the least energy)","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>43","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Use the diagram above to answer Questions below   Which of the transitions will produce emission of highest frequency?","images":["data:image/png;base64,"],"options":{"A":"V","B":"IV","C":"III","D":"II"},"answer":"A","explanation":"The one with the most energy produces the highest frequency  \u0394E for V = 0.0 - (-12.0) = 0.0 + 12.0 = 12.0 eV (which is the most energy)","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>44","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The following statements relate to atomic spectrum  I. All elements emit and absorb characteristic spectra  II. Spectral analysis is an important method of identifying environmental pollutants  III. The chemical composition of stars could be determined using spectral analysis","images":[],"options":{"A":"I, II and III","B":"II and III only","C":"I and III only","D":"I and II only"},"answer":"A","explanation":"Atomic spectra is the spectrum of the electromagnetic radiation emitted or absorbed by an electron during transitions between different energy levels within an atom. When an electron gets excited from one energy level to another, it either emits or absorbs light of a specific wavelength.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>45","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"A metal has a work function of 4.375 eV. Calculate its threshold frequency  [h = 6.6 x 10-34 Js, 1 eV = 1.6 x 10-19 J]","images":[],"options":{"A":"2.01 x 1015 Hz","B":"1.06 x 1015 Hz","C":"6.30 x 1014 Hz","D":"1.60 x 1014 Hz"},"answer":"B","explanation":"W = hfo; W = 4.375 eV = 4.375 x 1.6 x 10-19 J    ==> 4.375 x 1.6 x 10-19 = 6.6 x 10-34 x fo    =fo=4.375 x 1.6 x 10-196.6 x 10-34=7 x 10-196.6 x 10-34  \u2234  fo = 1.06 x 1015 Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>46","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The half-life of a radioactive substance is","images":[],"options":{"A":"its average life time","B":"one-half the value of its decay constant","C":"the length of time needed by the substance to decay completely","D":"the length of time during which the activity of the substance reduces by 50%"},"answer":"D","explanation":"The time-interval in which the mass of a radioactive substance or the number of its atoms, is reduced to half its initial value is called the half-life.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1999>47","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The half-life of a radioactive element is 5 s. Calculate its decay constant","images":[],"options":{"A":"0.113 s-1","B":"0.136 s-1","C":"0.139 s-1","D":"0.193 s-1"},"answer":"C","explanation":"\u03bb=0.693t1/2=0.6935=0.139s-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>48","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"A sheet of paper is placed in the path of the following radiations  I. Alpha particles II. Beta particles III. Gamma rays  Which of the radiations will pass through the sheet of paper","images":[],"options":{"A":"I only","B":"II only","C":"I and II only","D":"II and III only"},"answer":"D","explanation":"Alpha particles can't go through paper, but beta particles and gamma rays can. When the three types of radiation hit the aluminium, only the gamma rays get through. Beta particles can get through paper but the aluminium stops them.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1999>49","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Which of the following are the essential parts of an atomic bomb?","images":[],"options":{"A":"Uranium and neutrons","B":"Radium and polonium","C":"Nitrogen and neutrons","D":"Uranium and \u03b1-particles"},"answer":"A","explanation":"An atomic bomb relies on nuclear fission, where the nucleus of an atom splits into two smaller nuclei. The process releases a large amount of energy. The most common materials used for this are isotopes of uranium or plutonium. Neutrons are used to initiate the fission process. Therefore, the essential parts of an atomic bomb are uranium and neutrons.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1999>50","subject":"Physics","year":"1999","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Which of the following is not a safety precaution in a nuclear station?","images":[],"options":{"A":"Radioactive materials are stored in gas casings","B":"Radioactive materials are handled with remote controlled tongs","C":"Technicians in nuclear stations wear radio sensitive badges which are checked regularly","D":"Radioactive materials are kept in thick-walled lead container"},"answer":"A","explanation":"The safety of operating staff is a prime concern in nuclear plants. Radiation exposure is minimised by the use of remote handling equipment for many operations in the core of the reactor. Other controls include physical shielding and limiting the time workers spend in areas with significant radiation levels.","marks":"1","difficulty":"2"}];